// FindFieldSpec returns the field spec for a one-based field order in a PGN.
func FindFieldSpec(pgn uint32, fieldOrder uint8) (*FieldSpec, bool) {
	specs, exists := PgnFieldSpecMap[pgn]
	if !exists {
		return nil, false
	}
	for _, spec := range specs {
		if spec.FieldOrder == fieldOrder {
			return spec.FieldSpec, true
		}
	}
	return nil, false
}

